	var labelsMap map[string]string

	// 直接使用 RequestContext 提取 instance
	instance = extractInstance(c, req)
	labelsMap = extractLabelsMap(req)
	
	// 打印更详细的调试信息
	logger.Debug("Request labels: labels_set=%v, label_list_set=%v, labels=%v, label_list=%v",
		req.IsSetLabels(), req.IsSetLabelList(), req.GetLabels(), req.GetLabelList())
	if c != nil {
		logger.Debug("Client info: client_ip=%s", c.ClientIP())
	}

	global_lbs := []string{"app_id", req.GetAppID()}
	if req.IsSetLabelList() && len(req.GetLabelList())%2 == 0 {
		global_lbs = append(global_lbs, req.GetLabelList()...)
	}
	if req.IsSetLabels() {
		for k, v := range req.GetLabels() {
			global_lbs = append(global_lbs, k, v)
		}
	}

	// 打印调试日志：收到的指标数据量
	metricCount := len(req.Metrics)
	logger.Debug("Received metrics batch - app_id=%s, instance=%s, metric_count=%d", 
		req.GetAppID(), instance, metricCount)

